    SELECT ticket_no FROM tickets WHERE book_ref = '123456'
),
filtered_ticket_flights AS (
    SELECT tf.* FROM ticket_flights tf JOIN filtered_tickets ft ON tf.ticket_no = ft.ticket_no
)
SELECT * FROM filtered_ticket_flights;

